CREATE TABLE IF NOT EXISTS WhatsAppSetting (clinicId VARCHAR(64) PRIMARY KEY, phoneNumberId VARCHAR(120), businessAccountId VARCHAR(120), accessToken TEXT, webhookVerifyToken VARCHAR(255), apiVersion VARCHAR(20) DEFAULT 'v23.0', simulationMode TINYINT DEFAULT 1, currency VARCHAR(10) DEFAULT 'PKR', updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS WhatsAppTemplate (id VARCHAR(64) PRIMARY KEY, clinicId VARCHAR(64) NOT NULL, name VARCHAR(180) NOT NULL, category VARCHAR(30) NOT NULL, language VARCHAR(20) DEFAULT 'en', messageType VARCHAR(30) DEFAULT 'template', body TEXT NOT NULL, status VARCHAR(30) DEFAULT 'draft', purpose VARCHAR(30) DEFAULT 'service', createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS WhatsAppConversation (id VARCHAR(64) PRIMARY KEY, clinicId VARCHAR(64) NOT NULL, clientId VARCHAR(64) NOT NULL, status VARCHAR(30) DEFAULT 'open', assignedTo VARCHAR(64), lastMessageAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP, unreadCount INT DEFAULT 0, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY UX_WhatsAppConversation_Client (clinicId, clientId));
CREATE TABLE IF NOT EXISTS WhatsAppMessage (id VARCHAR(64) PRIMARY KEY, clinicId VARCHAR(64) NOT NULL, conversationId VARCHAR(64) NOT NULL, clientId VARCHAR(64) NOT NULL, direction VARCHAR(20) NOT NULL, purpose VARCHAR(30) DEFAULT 'support', messageType VARCHAR(30) DEFAULT 'text', body TEXT, mediaUrl TEXT, templateName VARCHAR(180), metaMessageId VARCHAR(255), deliveryStatus VARCHAR(30) DEFAULT 'queued', sentBy VARCHAR(64), cost DECIMAL(12,4) DEFAULT 0, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS WhatsAppAutomation (id VARCHAR(64) PRIMARY KEY, clinicId VARCHAR(64) NOT NULL, name VARCHAR(180) NOT NULL, triggerType VARCHAR(80) NOT NULL, triggerValue VARCHAR(120), actionType VARCHAR(80) DEFAULT 'send_template', templateId VARCHAR(64), purpose VARCHAR(30) DEFAULT 'service', isActive TINYINT DEFAULT 1, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS WhatsAppCampaign (id VARCHAR(64) PRIMARY KEY, clinicId VARCHAR(64) NOT NULL, name VARCHAR(180) NOT NULL, segment VARCHAR(80) NOT NULL, templateId VARCHAR(64), mediaType VARCHAR(30) DEFAULT 'text', mediaUrl TEXT, offerCode VARCHAR(100), status VARCHAR(30) DEFAULT 'draft', scheduledAt DATETIME, sentCount INT DEFAULT 0, deliveredCount INT DEFAULT 0, readCount INT DEFAULT 0, responseCount INT DEFAULT 0, conversionCount INT DEFAULT 0, revenue DECIMAL(14,2) DEFAULT 0, createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
